function ProductCard({ product, onAddToCart }) {
  return (
    <div style={{
      border: '1px solid #ddd',
      borderRadius: 12,
      padding: 20,
      textAlign: 'center',
    }}>
      <div style={{ fontSize: 48 }}>{product.emoji}</div>
      <h3>{product.name}</h3>
      <p style={{ fontWeight: 'bold' }}>${product.price.toFixed(2)}</p>
      <button
        onClick={() => onAddToCart(product)}
        style={{
          padding: '8px 16px',
          backgroundColor: '#1976d2',
          color: 'white',
          border: 'none',
          borderRadius: 6,
          cursor: 'pointer',
        }}
      >
        Add to Cart
