function ShoppingCart({ items, onRemove }) {
  const total = items.reduce((sum, item) => sum + item.price, 0);

  return (
    <div style={{
      border: '2px solid #1976d2',
      borderRadius: 12,
      padding: 20,
      marginTop: 24,
    }}>
      <h2>Shopping Cart ({items.length})</h2>
      {items.length === 0 ? (
        <p>Your cart is empty.</p>
      ) : (
        <>
          {items.map((item, index) => (
            <div
              key={index}
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                padding: '8px 0',
                borderBottom: '1px solid #eee',
              }}
            >
              <span>{item.name}</span>
              <span>
                ${item.price.toFixed(2)}{' '}
                <button onClick={() => onRemove(index)}>X</button>
              </span>
            </div>
          ))}
          <h3 style={{ marginTop: 12 }}>
            Total: ${total.toFixed(2)}
          </h3>
        </>
      )}
    </div>
  );
}

export default function Store() {
  const [cart, setCart] = useState([]);

  const addToCart = (product) => {
    setCart([...cart, product]);
  };

  const removeFromCart = (index) => {
    setCart(cart.filter((_, i) => i !== index));
  };

  return (
    <div style={{ maxWidth: 700, margin: '0 auto', padding: 32 }}>
      <h1>Dev Merch Store</h1>
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(3, 1fr)',
        gap: 16,
      }}>
        {products.map((product) => (
          <ProductCard
            key={product.id}
            product={product}
            onAddToCart={addToCart}
          />
        ))}
      </div>
      <ShoppingCart items={cart} onRemove={removeFromCart} />
    </div>
  );
}

function StatCard({ label, value, change, color }) {
  const isPositive = change >= 0;

  return (
    <div style={{
      border: '1px solid #ddd',
      borderRadius: 12,
      padding: 20,
      borderTop: `4px solid ${color}`,
    }}>
      <p style={{ color: '#666', margin: 0, fontSize: 14 }}>{label}</p>
      <h2 style={{ margin: '8px 0' }}>{value}</h2>
      <p style={{
        margin: 0,
        fontSize: 14,
        color: isPositive ? 'green' : 'red',
      }}>
        {isPositive ? '+' : ''}{change}% from last month
      </p>
    </div>
  );
}

function SimpleBarChart({ data }) {
  const max = Math.max(...data.map((d) => d.value));

  return (
    <div style={{
      border: '1px solid #ddd',
      borderRadius: 12,
      padding: 20,
    }}>
      <h3>Weekly Visitors</h3>
      <div style={{ display: 'flex', alignItems: 'flex-end', gap: 8, height: 120 }}>
        {data.map((d) => (
          <div key={d.day} style={{ textAlign: 'center', flex: 1 }}>
            <div
              style={{
                height: `${(d.value / max) * 100}px`,
                backgroundColor: '#1976d2',
                borderRadius: '4px 4px 0 0',
              }}
            />
            <p style={{ fontSize: 12, margin: '4px 0 0' }}>{d.day}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

