import { useState } from 'react';

function PostCard({ post, onLike, onComment }) {
  const [commentText, setCommentText] = useState('');

  const handleSubmitComment = () => {
    if (commentText.trim()) {
      onComment(post.id, commentText);
      setCommentText('');
    }
  };

  return (
    <div style={{
      border: '1px solid #ddd',
      borderRadius: 12,
      padding: 20,
      marginBottom: 16,
    }}>
      {/* Post header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
        <div style={{
          width: 40, height: 40, borderRadius: '50%',
          backgroundColor: '#1976d2', color: 'white',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontWeight: 'bold',
        }}>
          {post.author[0]}
        </div>
        <div>
          <strong>{post.author}</strong>
          <p style={{ margin: 0, fontSize: 12, color: '#666' }}>{post.time}</p>
        </div>
      </div>

      {/* Post content */}
      <p style={{ marginTop: 12 }}>{post.content}</p>

      {/* Like button */}
      <button
        onClick={() => onLike(post.id)}
        style={{
          background: 'none', border: 'none', cursor: 'pointer',
          fontSize: 16, color: post.liked ? 'red' : '#666',
        }}
      >
        {post.liked ? '\u2764' : '\u2661'} {post.likes}
      </button>

      {/* Comments */}
      {post.comments.map((comment, i) => (
        <div key={i} style={{
          backgroundColor: '#f5f5f5', borderRadius: 8,
          padding: '8px 12px', marginTop: 8, fontSize: 14,
        }}>
          <strong>{comment.author}:</strong> {comment.text}
        </div>
      ))}

      {/* Add comment */}
      <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
        <input
          value={commentText}
          onChange={(e) => setCommentText(e.target.value)}
          placeholder="Write a comment..."
          style={{
            flex: 1, padding: 8, borderRadius: 8,
            border: '1px solid #ddd',
          }}
        />
        <button onClick={handleSubmitComment}>Post</button>
      </div>
    </div>
  );
}

export default function SocialFeed() {
  const [posts, setPosts] = useState([
    {
      id: 1,
      author: 'Alice',
      time: '2 hours ago',
      content: 'Just finished my first React project! It is a todo app and I am so proud of it.',
      likes: 12,
      liked: false,
      comments: [
        { author: 'Bob', text: 'Great job! Keep it up!' },
      ],
    },
    {
      id: 2,
      author: 'Charlie',
      time: '5 hours ago',
      content: 'Can anyone recommend a good tutorial for learning CSS Grid?',
      likes: 5,
      liked: false,
      comments: [],
    },
  ]);

  const handleLike = (postId) => {
    setPosts(posts.map((post) =>
      post.id === postId
        ? { ...post, liked: !post.liked, likes: post.liked ? post.likes - 1 : post.likes + 1 }
        : post
    ));
  };

  const handleComment = (postId, text) => {
    setPosts(posts.map((post) =>
      post.id === postId
        ? { ...post, comments: [...post.comments, { author: 'You', text }] }
        : post
    ));
  };

  return (
    <div style={{ maxWidth: 500, margin: '0 auto', padding: 32 }}>
      <h1>Dev Feed</h1>
      {posts.map((post) => (
        <PostCard
          key={post.id}
          post={post}
          onLike={handleLike}
          onComment={handleComment}
        />
      ))}
    </div>
  );
}

