import { useState } from 'react';

function MessageBubble({ message, isOwn }) {
  return (
    <div style={{
      display: 'flex',
      justifyContent: isOwn ? 'flex-end' : 'flex-start',
      marginBottom: 8,
    }}>
      <div style={{
        maxWidth: '70%',
        padding: '10px 16px',
        borderRadius: 16,
        backgroundColor: isOwn ? '#1976d2' : '#f0f0f0',
        color: isOwn ? 'white' : '#333',
      }}>
        {!isOwn && (
          <p style={{ margin: 0, fontSize: 12, fontWeight: 'bold', marginBottom: 4 }}>
            {message.sender}
          </p>
        )}
        <p style={{ margin: 0 }}>{message.text}</p>
        <p style={{
          margin: 0, fontSize: 11, marginTop: 4,
          opacity: 0.7, textAlign: 'right',
        }}>
          {message.time}
        </p>
      </div>
    </div>
  );
}

export default function ChatApp() {
  const currentUser = 'You';

  const [messages, setMessages] = useState([
    { id: 1, sender: 'Alice', text: 'Hey! How is your React project going?', time: '10:30 AM' },
    { id: 2, sender: 'You',   text: 'Pretty good! I just learned about useState.', time: '10:31 AM' },
    { id: 3, sender: 'Alice', text: 'Nice! That is one of the most important hooks.', time: '10:32 AM' },
    { id: 4, sender: 'Bob',   text: 'useState and useEffect are the two big ones to learn first.', time: '10:33 AM' },
  ]);

  const [newMessage, setNewMessage] = useState('');

  const handleSend = () => {
    if (!newMessage.trim()) return;
    setMessages([
      ...messages,
      {
        id: messages.length + 1,
        sender: currentUser,
        text: newMessage,
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      },
    ]);
    setNewMessage('');
  };

  return (
    <div style={{
      maxWidth: 500, margin: '0 auto',
      border: '1px solid #ddd', borderRadius: 12,
      display: 'flex', flexDirection: 'column', height: 500,
    }}>
      {/* Header */}
      <div style={{
        padding: 16, borderBottom: '1px solid #ddd',
        fontWeight: 'bold', fontSize: 18,
      }}>
        #general
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: 'auto', padding: 16 }}>
        {messages.map((msg) => (
          <MessageBubble
            key={msg.id}
            message={msg}
            isOwn={msg.sender === currentUser}
          />
        ))}
      </div>

      {/* Input */}
      <div style={{
        display: 'flex', gap: 8, padding: 12,
        borderTop: '1px solid #ddd',
      }}>
        <input
          value={newMessage}
          onChange={(e) => setNewMessage(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Type a message..."
          style={{
            flex: 1, padding: 10, borderRadius: 20,
            border: '1px solid #ddd', outline: 'none',
          }}
        />
        <button
          onClick={handleSend}
          style={{
            padding: '10px 20px', borderRadius: 20,
            backgroundColor: '#1976d2', color: 'white',
            border: 'none', cursor: 'pointer',
          }}
        >
          Send
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';

export default function ClickGame() {
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(10);
  const [isPlaying, setIsPlaying] = useState(false);
  const [highScore, setHighScore] = useState(0);

  // Timer countdown
  useEffect(() => {
    if (!isPlaying || timeLeft <= 0) return;

    const timer = setTimeout(() => {
      setTimeLeft(timeLeft - 1);
    }, 1000);

    // When time runs out
    if (timeLeft === 1) {
      setTimeout(() => {
        setIsPlaying(false);
        if (score > highScore) {
          setHighScore(score);
        }
      }, 1000);
    }

    return () => clearTimeout(timer);
  }, [isPlaying, timeLeft, score, highScore]);

  const startGame = () => {
    setScore(0);
    setTimeLeft(10);
    setIsPlaying(true);
  };

  const handleClick = () => {
    if (isPlaying) {
      setScore(score + 1);
    }
  };

  return (
    <div style={{ textAlign: 'center', maxWidth: 400, margin: '0 auto', padding: 32 }}>
      <h1>Click Speed Challenge</h1>
      <p>How many times can you click in 10 seconds?</p>

      <div style={{
        fontSize: 48, fontWeight: 'bold',
        margin: '20px 0', color: '#1976d2',
      }}>
        {score}
      </div>

      <p style={{ fontSize: 24 }}>
        Time: {timeLeft}s
      </p>

      {isPlaying ? (
        <button
          onClick={handleClick}
          style={{
            width: 200, height: 200, borderRadius: '50%',
            fontSize: 24, fontWeight: 'bold',
            backgroundColor: '#1976d2', color: 'white',
            border: 'none', cursor: 'pointer',
          }}
        >
          CLICK ME!
        </button>
      ) : (
        <div>
          {score > 0 && (
            <p style={{ fontSize: 20 }}>
              You clicked {score} times!
              {score > highScore ? ' New high score!' : ''}
            </p>
          )}
          <button
            onClick={startGame}
            style={{
              padding: '14px 32px', fontSize: 18,
              backgroundColor: '#2e7d32', color: 'white',
              border: 'none', borderRadius: 8, cursor: 'pointer',
            }}
          >
            {score > 0 ? 'Play Again' : 'Start Game'}
          </button>
        </div>
      )}

      {highScore > 0 && (
        <p style={{ marginTop: 20, color: '#666' }}>
          High Score: {highScore}
        </p>
      )}
    </div>
  );
}
